import React from 'react';

const Home = () => {
  return (
    <div style={{ padding: '40px 8%', maxWidth: '1200px', margin: '0 auto' }}>
      {/* Banner Principal */}
      <div style={bannerStyle}>
        <div style={overlayStyle}>
          <h1 style={{ fontSize: '3rem', marginBottom: '10px' }}>OFERTAS APP</h1>
          <p style={{ fontSize: '1.2rem' }}>Encuentra los mejores precios en los locales de tu zona.</p>
        </div>
      </div>

      {/* Secciones de ejemplo */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '20px', marginTop: '40px' }}>
        <div style={cardStyle}>
          <h3>🛒 Supermercados</h3>
          <p>Mira las ofertas del día en productos de canasta básica.</p>
        </div>
        <div style={cardStyle}>
          <h3>👕 Indumentaria</h3>
          <p>Liquidaciones de temporada en locales adheridos.</p>
        </div>
      </div>
    </div>
  );
};

const bannerStyle = {
  height: '400px',
  borderRadius: '20px',
  backgroundImage: 'url("https://images.unsplash.com/photo-1542838132-92c53300491e?w=1000")',
  backgroundSize: 'cover',
  backgroundPosition: 'center',
  position: 'relative',
  overflow: 'hidden'
};

const overlayStyle = {
  position: 'absolute',
  inset: 0,
  background: 'rgba(0,0,0,0.5)',
  display: 'flex',
  flexDirection: 'column',
  justifyContent: 'center',
  alignItems: 'center',
  color: 'white',
  textAlign: 'center'
};

const cardStyle = {
  padding: '20px',
  background: 'white',
  borderRadius: '15px',
  boxShadow: '0 4px 6px rgba(0,0,0,0.05)',
  border: '1px solid #eee'
};

export default Home;
